class Solution {
public:
    vector<int> twoSum(vector<int>& nums, int target) {
        unordered_map<int, int> indices;
        for (int i = 0; i < nums.size(); i++) {
            if (indices.find(target - nums[i]) != indices.end()) {
                return {indices[target - nums[i]], i};
            }
            indices[nums[i]] = i;
        }
        return {};
    }
};

class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        int i=0,j=0;
	    int n=s.size();
	    map<char, int> m;
	    int ans=0;
	    while(j<n){
	        m[s[j]]++;
	        if(m.size()>j-i+1)
	        j++;
	        else if(m.size()==j-i+1){
	            ans=max(ans,j-i+1);
	            j++;
	        }
	        else{
	            while(m.size()<j-i+1){
	                m[s[i]]--;
	                if(m[s[i]]==0)
	                  m.erase(s[i]);
	                i++;
	            }
	            j++;
	        }
	    }

	    return ans;

    }
};

class Solution {
public:
    double mediann(vector<int>&a,vector<int>&b){
        int m=a.size();
        int n=b.size();
        if(m>n)
            return mediann(b,a);
        int l=0,r=m;
        while(l<=r){
            int partx=l+(r-l)/2;
            int party=(m+n+1)/2-partx;
            int maxlx=(partx==0)?INT_MIN:a[partx-1];
            int minrx=(partx==m)?INT_MAX:a[partx];
            int maxly=(party==0)?INT_MIN:b[party-1];
            int minry=(party==n)?INT_MAX:b[party];
            if(maxlx<=minry&&maxly<=minrx){
                if((m+n)%2==0)
                    return (double)(max(maxlx,maxly)+min(minrx,minry))/2;
                else
                    return (double)(max(maxlx,maxly));
            }else if(maxlx>minry)
                r=partx-1;
            else
                l=partx+1;
        }
        return -1.0;
    }
    double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {
        double ans;
        ans=mediann(nums1,nums2);
        return ans;   
    }
};

class Solution {
public:
    string longestPalindrome(string s) {
        int m=s.size();
        int dp[m][m];
        memset(dp,0,sizeof(dp));
        for(int i=0;i<m;i++){
            dp[i][i]=1;
        }
        int start=0,end=1;
        for(int i=0;i<m-1;i++){
            if(s[i]==s[i+1]){
                dp[i][i+1]=1;
                start=i;
                end=2;
            }
        }
        for(int i=2;i<m;i++){
            for(int j=0;j<m-i;j++){
              if(dp[j+1][i+j-1]==1 && s[j]==s[i+j]){
                  dp[j][i+j]=1;
                  start=j;
                  end=i+1;
              }   
           }
        }
        return s.substr(start,end);
    }
};

class Solution {
public:

    bool solve(string &s, string &p, int n, int m){
        if(n==0 && m==0)
            return true;
        if(n==0 && m!=0){
            if(p[m-1]=='*')
                return solve(s,p,n,m-2);
            return false;
        }
        if(n!=0 && m==0)
            return false;

        if(s[n-1]==p[m-1] || p[m-1]=='.')
            return solve(s,p,n-1,m-1);

        else if(p[m-1]=='*'){
            //0 characters match
            if(solve(s,p,n,m-2))
                return true;
            //if previous character matches
            if(s[n-1]==p[m-2] || p[m-2]=='.')
                return solve(s,p,n-1,m);
            return false;
        }
        return false;
    }

    bool isMatch(string s, string p) {
        int n=s.size();
        int m=p.size();
        return solve(s,p,n,m);
    }
};

class Solution {
public:
    int maxArea(vector<int>& height) {
        int l=0;
        int r=height.size()-1;
        int area=INT_MIN;
        while(l<r)
        {
            int h = min(height[l],height[r]);
            int w = r-l;
            area=max(area,h*w);
            if(height[l]<height[r])
            {
                l++;
            }
            else
            {
                r--;
            }
        }
        return area;
    }
};

