class Solution {
public:
    class Trie{
        public:
        Trie *child[26]; //child pointers
        bool isEnd;
        int count;

        Trie(){
            for(int i=0;i<26;i++)
                child[i]=NULL;
            isEnd=false;
            count=0;
        }
    };
    Trie* root=new Trie();

    void insert(string s){
        Trie* curr=root;
        for(int i=0;i<s.size();i++){
            char ch=s[i]-'a';
            if(curr->child[ch]==NULL)
                curr->child[ch]=new Trie();

            curr=curr->child[ch];
            curr->count++;
        }
        curr->isEnd=true;

    }

    string longestCommonPrefix(vector<string>& strs) {
        int n=strs.size();
        if(n==1)
            return strs[0];
        int c=0;
        for(int i=0;i<n;i++){
            string s=strs[i];
            int v=s.size();
            if(v!=0){
                insert(s);
            }
        }
        //lcp in all strings therefore, count must be n, first string ko reference le k soch skte hai kyuki agar lcp usse chota hua to theek h aur usse bda hua to sare string me waise hi ni aapayega
        string ref=strs[0];
        int sz=ref.size();
        Trie* temp=root;
        string ans;
        for(int i=0;i<sz;i++){
            char ch=ref[i]-'a';
            if(temp->child[ch]!=NULL && temp->child[ch]->count==n)
                ans.push_back(ref[i]);
            else break;
            temp=temp->child[ch];
        }
        return ans;
    }
};

class Solution {
public:
    vector<vector<int>> ans;

    vector<vector<int>> threeSum(vector<int>& nums) {
        int n=nums.size();
        if(n==0)
            return ans;
        sort(nums.begin(), nums.end());
        for(int i=0;i<n;i++){
            if(i>0 && nums[i]==nums[i-1])
                continue;
            int l=i+1, r=n-1;
            while(l<r){
                int s=nums[i]+nums[l]+nums[r];
                if(s>0)
                    r--;
                else if(s<0)
                    l++;
                else{
                    ans.push_back({nums[i], nums[l], nums[r]});
                    while(l<r && nums[l]==nums[l+1])
                        l++;
                    while(l<r && nums[r]==nums[r-1])
                        r--;
                    l++;
                    r--;
                }
            }

        }
        return ans;
    }
};

class Solution {
public:
    vector<string> ans;
    unordered_map<char, string> m;


    void backtrack(int p, string s, string d){
        if(s.size()==d.size()){
            ans.push_back(s);
            return;
        }
        for(int i=p;i<d.size();i++){
            char c=d[i];
            for(int j=0;j<m[c].size();j++){
                char ch=m[c][j];
                s.push_back(ch);
                backtrack(i+1, s, d);
                s.pop_back();
            }
        }
    }

    vector<string> letterCombinations(string digits) {
