};

class Solution {
public:
    vector<vector<int>> fourSum(vector<int>& a, int t) {
       int n=a.size();
        sort(a.begin(), a.end());
        vector<vector<int>> ans;
        if(n<4)
            return ans;
        for(int i=0;i<n-3;i++){
            while(i>0 && a[i]==a[i-1])
                i++;
            for(int j=i+1;j<n-2;j++){
                while(j>i+1 && a[j]==a[j-1])
                    j++;
                long long sum=t-a[i]-a[j];
                int l=j+1, r=n-1;
                while(l<r){
                    int s1=a[l]+a[r];
                    if(s1>sum)
                        r--;
                    else if(s1<sum)
                        l++;
                    else{
                        ans.push_back({a[i], a[j], a[l], a[r]});
                        l++;
                        r--;
                        while(a[l]==a[l-1] && l<r)
                            l++;
                        while(a[r]==a[r+1] && l<r)
                            r--;
                    }
                }
            }
        }
        return ans;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* removeNthFromEnd(ListNode* head, int n) {
        ListNode* dummy=new ListNode(0);
        dummy->next=head;
        ListNode* f=dummy;
        ListNode* s=dummy;
        int k=0;
        while(k<n){
            f=f->next;
            k++;
        }
        while(f->next!=NULL){
            f=f->next;
            s=s->next;
        }
        s->next=s->next->next;
        return dummy->next;
    }
};

class Solution {
public:
    bool isValid(string s) {
        stack<char> st;
        int n=s.size();
        if(n%2!=0)
            return false;
        for(int i=0;i<n;i++){
           if(s[i]=='('  || s[i]=='{' || s[i]=='[') 
            st.push(s[i]);

            if(s[i]==')') {
                if(!st.empty() && st.top()=='('){
                    st.pop();
                }
                else
                    return false;
            }

            if(s[i]=='}') {
                if(!st.empty() && st.top()=='{'){
                    st.pop();
                }
                else
                    return false;
            }

            if(s[i]==']') {
                if(!st.empty() && st.top()=='['){
                    st.pop();
                }
                else
                    return false;
            }

        }
        if(st.empty())
            return true;
        else
            return false;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:

    ListNode* mergeTwoLists(ListNode* l1, ListNode* l2) {
        if(l1 == NULL){
			return l2;
		}
		if(l2 == NULL){
			return l1;
		}        
		if(l1->val < l2->val){
			l1->next = mergeTwoLists(l1->next, l2);
			return l1;
		}
		else{
			l2->next = mergeTwoLists(l1, l2->next);
			return l2;            
		}
    }
};

class Solution {
public:

    void backtrack(int open, int close, string s, vector<string> &ans, int n){
        if(s.size()==2*n){
            ans.push_back(s);
            return;
        }
        if(open<n){
            s.push_back('(');
            backtrack(open+1, close, s, ans, n);
            s.pop_back();
        }
        if(close<open){
            s.push_back(')');
            backtrack(open, close+1, s, ans, n);
            s.pop_back();
        }
    }

    vector<string> generateParenthesis(int n) {
        string s="";
        vector<string> ans;
        backtrack(0,0,s,ans,n);
        return ans;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:

    struct comp{
        bool operator()(ListNode* a, ListNode* b){
        return a->val>b->val;
        }
    };

    ListNode* mergeKLists(vector<ListNode*>& lists) {
        int n=lists.size();
        if(n==0)
            return NULL;
        if(n==1)
            return lists[0];
        priority_queue<ListNode*, vector<ListNode*>, comp> pq;
        for(int i=0;i<n;i++){
            ListNode* head=lists[i];
            while(head!=NULL){
                ListNode* t=head->next;
                head->next=NULL;
                pq.push(head);
                head=t;
            }
        }
        ListNode* dummy = new ListNode(0);
        ListNode* temp=dummy;
        while(!pq.empty()){
            temp->next=pq.top();
            pq.pop();
            temp=temp->next;
        }
        return dummy->next;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* swapPairs(ListNode* head) {
        ListNode *dummy = new ListNode(0), *node;
    node = dummy;
    dummy->next = head;
    while (head && head->next) {
        ListNode *nxt = head->next;
        head->next = nxt->next;
        nxt->next = head;
        node->next = nxt;
        node = head;
        head = node->next;
    }
    return dummy->next;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* reverseKGroup(ListNode* head, int k) {
            ListNode *p1=head,*p2=head;
            ListNode *first=NULL,*cur=head;
            int n=0;
            while(p1)
            {
                p1=p1->next;
                n++;
            }
            n=n/k;
            if(n==0 || k==1) 
                return head;
            for(int i=0;i<n;i++)
            {
                ListNode *prev=NULL,*next=NULL;
                int l=1;
                p1=cur;
                while(l++<=k)
                {
                    next=cur->next;
                    cur->next=prev;
                    prev=cur;
                    cur=next;
                }
                if(i>=1)
                    first->next=prev;
                else
                    p2=prev;
                first=p1;
            }
            first->next=cur;
            return p2;
    }
};

class Solution {
public:
    int divide(int dividend, int divisor) {
        if(dividend==INT_MIN && divisor==-1) return INT_MAX;
        if(dividend==INT_MIN && divisor==1) return INT_MIN;

        long int dd = abs(dividend), dv = abs(divisor);
        int res=0;

        while(dv<=dd) {
            long int mul=dv, tmp=1;
            while(mul<=dd-mul) {
                mul+=mul;
                tmp+=tmp;
            }
            res+=tmp;
            dd-=mul;
        }

        //If either of dividend or divisor is negative our result will be negative
        if((dividend<0&&divisor>0) || (dividend>0&&divisor<0)) return -res;

        return res;
    }
};

