class Solution {
public:
    void nextPermutation(vector<int>& nums) {
        int n=nums.size();
        int i=n-2;
        while(i>=0 && nums[i]>=nums[i+1]){
            i--;
        }
        if(i>=0){
            int j=n-1;
            while(nums[j]<=nums[i]){
                j--;
            }
            swap(nums[i], nums[j]);
        }
        reverse(nums.begin()+i+1, nums.end());
    }
};

class Solution {
public:
    int longestValidParentheses(string s) {
        int n=s.size();
        if(n==0)
            return 0;
        int dp[n];  // dp[i] denotes longestValidParentheses till i
        int ans=0;
        for(int i=0;i<n;i++)
            dp[i]=0;
        for(int i=1;i<n;i++){
            if(s[i]=='(')
                dp[i]=0;
            else{
                if(s[i-1]=='('){
                    if(i>=2){
                        dp[i]=dp[i-2]+2;
                    }
                    else
                        dp[i]=2;
                }
                else if(i-dp[i-1]>0 && s[i-dp[i-1]-1]=='('){
                    if(i-dp[i-1]>=2)
                        dp[i]=dp[i-1]+dp[i-dp[i-1]-2]+2;
                    else
                        dp[i]=dp[i-1]+2;   
                }
                ans=max(ans,dp[i]);
            }
        }
        return ans;
    }
};

class Solution {
public:
    int search(vector<int>& nums, int target) {
        int n=nums.size();
        int l=0, r=n-1;
        while(l<=r){
            int mid=l+(r-l)/2;
            if(nums[mid]==target)
                return mid;
            else if(nums[l]<=nums[mid]){ //left half sorted
                if(target>=nums[l] && target<=nums[mid])
                    r=mid-1;
                else 
                    l=mid+1;
            }
            else{ //right half sorted
                if(target>=nums[mid] && target<=nums[r])
                    l=mid+1;
                else
                    r=mid-1;
            }
        }
        return -1;
    }
};

class Solution {
public:
    
    int lowerbound(vector<int>& nums, int target){
       int l=0,h=nums.size()-1;
       while(l<=h){
            int mid=l+(h-l)/2;
            if(nums[mid]<target)
                l=mid+1;
            else
                h=mid-1; 
       }
        return l;
    }
    vector<int> searchRange(vector<int>& nums, int target) {
       vector<int> ans(2);
        ans[0]=-1;
        ans[1]=-1;
       int l=lowerbound(nums, target);
       int r=lowerbound(nums, target+1)-1;
       if(l<nums.size() && nums[l]==target){
            return {l,r};
        }
        return ans;
    }
};

