        }
        for(int i=r,j=c;i<m && j>=0;i++,j--){ //left lower diagonal
            if(temp[i][j]=='1')
                return false;
        }
        for(int i=r,j=c;i>=0 && j>=0;i--,j--){ //left upper diagonal
            if(temp[i][j]=='1')
                return false;
        }
        return true;
    }

