            fc[endchar]--;
            if(fc[endchar] >= 0) // Important detail of the this algo.
                tsize--;

            end++;

            while(tsize == 0){
                int curlen = end - begin;
                if(curlen < minl) {
                    minl = curlen;
                    ans = s.substr(begin, minl);
                }


                char beginchar = s[begin];
                fc[beginchar]++;
                if(fc[beginchar] > 0)  // Another important detail of the this algo.
                    tsize++;
                begin++;
            }
        }

        return ans;
    }
};

class Solution {
public:

    void backtrack(vector<int> &t, vector<vector<int>> &ans, int st, int n, int k){
        if(t.size()==k)
        {
            ans.push_back(t);
            return;
        }

        for(int i=st;i<n;i++){
            t.push_back(i+1);
            backtrack(t,ans,i+1,n,k);
            t.pop_back();
        }
    }

    vector<vector<int>> combine(int n, int k) {
        vector<vector<int>> ans;
        if(n<k)
            return ans;
        vector<int> t;
        backtrack(t,ans,0,n,k);
        return ans;
    }
};

