/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* deleteDuplicates(ListNode* head) {
        if(head==NULL || head->next==NULL)
            return head;

        ListNode* dummy = new ListNode(0, head);
        ListNode* temp=head;
        ListNode* prev=dummy;

        while(temp!=NULL){
            if(temp->next!=NULL && temp->val == temp->next->val){
                while(temp->next!=NULL && temp->val == temp->next->val)
                    temp=temp->next;
                prev->next=temp->next;
            }
            else if(prev->next!=NULL)
                prev=prev->next;
            temp=temp->next;      
        }
        return dummy->next;
    }
};

class Solution {
public:
    //VERY IMP: atleast one bar is fully included in the largest rectangle

    // If largest rectangle contains atleast one bar full then if we consideer largest of all areas containing every bar fully we get our answer

    //find nearest left bar with height < curr bar and do same for right.
    int largestRectangleArea(vector<int>& h) {
        int n=h.size();
        int l[n], r[n];
        stack<int> s;
        for(int i=0;i<n;i++){
            if(s.empty())
                l[i]=0;
            else{
                while(!s.empty() && h[s.top()]>=h[i])
                    s.pop();
                if(s.empty())
                    l[i]=0;
                else
                    l[i]=s.top()+1;
            }
            s.push(i);
        }
        while(!s.empty())
            s.pop();
        for(int i=n-1;i>=0;i--){
            if(s.empty())
                r[i]=n-1;
            else{
                while(!s.empty() && h[s.top()]>=h[i])
                    s.pop();
                if(s.empty())
                    r[i]=n-1;
                else
                    r[i]=s.top()-1;
            }
            s.push(i);
        }
        int ans=0;
        for(int i=0;i<n;i++){
            ans=max(ans, h[i]*(r[i]-l[i]+1));
        }
        return ans;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* partition(ListNode* head, int x) {
        ListNode* x1=new ListNode(0); //all nodes less than x
        ListNode* x2=new ListNode(0); //all nodes >=x
        ListNode* t1=x1;
        ListNode* t2=x2;
        ListNode* temp=head;
        while(temp!=NULL){
            if(temp->val<x){
                t1->next=temp;
                t1=temp;
            }
            else{
                t2->next=temp;
                t2=temp;
            }
            temp=temp->next;
        }
        t2->next=NULL;
        t1->next=x2->next;
        return x1->next;
    }
};

class Solution {
