    void merge(vector<int>& nums1, int m, vector<int>& nums2, int n) {
        int i=m-1,j=n-1,c=m+n-1;
        while(i>=0 && j>=0){
            if(nums1[i]<nums2[j]){
                nums1[c]=nums2[j];
                j--;
                c--;
            }
            else
            {
                nums1[c]=nums1[i];
                i--;
                c--;
            }
        }
        while(i>=0){
            nums1[c]=nums1[i];
            i--;
            c--;
        }
        while(j>=0){
            nums1[c]=nums2[j];
            j--;
            c--;
        }
    }
};

class Solution {
public:
    vector<int> grayCode(int n) {
        vector<int> result;
        result.push_back(0);

        for (int i = 1; i <= n; i++) {
            int prevLength = result.size();
            int mask = 1 << (i - 1);
            for (int j = prevLength - 1; j >= 0; j--) {
                result.push_back(mask + result[j]);
            }
        }
        return result;
    }
};

