 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:

    TreeNode* solve(vector<int>& pre, vector<int>& in, int p, int s, int e){
        if(p>=pre.size() || s>e)
            return NULL;
        TreeNode* root= new TreeNode(pre[p]);
        int ind;
        for(int i=s;i<=e;i++){
            if(in[i]==pre[p]){
                ind=i;
                break;
            }
        }
        root->left=solve(pre,in,p+1,s,ind-1);
        root->right=solve(pre,in,p+ind-s+1,ind+1,e);

        return root;

    }

    TreeNode* buildTree(vector<int>& pre, vector<int>& in) {
        return solve(pre,in,0,0,pre.size()-1);
    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    TreeNode* build(vector<int>& preorder, vector<int>& inorder, int &ps, int is, int ie) {
         if(ps<0 || is>ie)
             return NULL;

         TreeNode* root= new TreeNode(preorder[ps]);
         int index;
         for(int i=is; i<=ie;i++){
             if(preorder[ps]==inorder[i]){
                 index=i;
                 break;
             }
         }
         ps--;

         root->right=build(preorder,inorder,ps, index+1, ie);
         root->left=build(preorder,inorder,ps,is, index-1);

         return root;
     }

    TreeNode* buildTree(vector<int>& inorder, vector<int>& post) {
        int m=post.size()-1;
        return build(post, inorder, m,0, inorder.size()-1);
    }
};

