 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:

    TreeNode* solve(ListNode* head, ListNode* tail){
        if(head==tail)
            return NULL;
        ListNode* slow=head;
        ListNode* fast=head;
        while(fast!=tail && fast->next!=tail){
            slow=slow->next;
            fast=fast->next->next;
        }
        // if(fast)
        //     slow=slow->next;
        TreeNode* root=new TreeNode(slow->val);
        root->left=solve(head, slow);
        root->right=solve(slow->next, tail);
        return root;
    }

    TreeNode* sortedListToBST(ListNode* head) {
        return solve(head, NULL);
    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    int solve(TreeNode* root){
        if(root==NULL)
            return 0;
        int l=solve(root->left);
        if(l==-1)
            return -1;
        int r=solve(root->right);
        if(r==-1)
            return -1;
        if(abs(l-r)>1)
            return -1;
        return max(l,r)+1;
    }
    bool isBalanced(TreeNode* root) {
        if(root==NULL)
            return true;
        if(solve(root)==-1)
            return false;
        return true;
    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    int solve(TreeNode* root){
        if(root==NULL)
            return 0;
        if(root->left==NULL && root->right==NULL)
            return 1;
        if(root->left==NULL)
            return 1+solve(root->right);
        if(root->right==NULL)
            return 1+solve(root->left);
        int l,r;
        l=solve(root->left);
        r=solve(root->right);
        return 1+min(l,r);
    }
    int minDepth(TreeNode* root) {
        if(root==NULL)
            return 0;
        return solve(root);
    }
};

/**
