    bool solve(TreeNode* root, int t, int sum){
        if(root==NULL)
            return false;
        sum+=root->val;
        if(sum==t && root->left==NULL && root->right==NULL)
            return true;
        bool l=solve(root->left, t, sum);
        bool r=solve(root->right, t, sum);
        return l||r;
    }
    bool hasPathSum(TreeNode* root, int t) {
        return solve(root, t, 0);
    }
};

