    vector<vector<int>> ans;

    bool solve(TreeNode* root, int t, int sum, vector<int> v){
        if(root==NULL)
            return false;
        sum+=root->val;
        v.push_back(root->val);
        if(sum==t && root->left==NULL && root->right==NULL){
            ans.push_back(v);
            return true;
        }

        bool l=solve(root->left, t, sum, v);
        bool r=solve(root->right, t, sum, v);
        return l||r;
    }

    vector<vector<int>> pathSum(TreeNode* root, int t) {
        vector<int> v;
        solve(root, t, 0, v);
        return ans;
    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    void flatten(TreeNode* root) {
        if(root==NULL)
            return;
        while(root!=NULL){
            if(root->left!=NULL){
                TreeNode* tl=root->left;
                TreeNode* curr=tl;
                while(curr->right!=NULL)
                    curr=curr->right;
                curr->right=root->right; //Morris Traversal
                root->left=NULL;
                root->right=tl;
            }
            root=root->right;
        }
    }
};

class Solution {
public:
    int numDistinct(string s, string t) {
        int m=s.size();
        int n=t.size();
        long long dp[m+1][n+1];
        dp[0][0]=1;
        for(int i=1;i<=m;i++)
            dp[i][0]=1;
        for(int i=1;i<=n;i++)
            dp[0][i]=0;
        for(int i=1;i<=m;i++){
            for(int j=1;j<=n;j++){
                if(s[i-1]==t[j-1]){
                    dp[i][j]=dp[i-1][j-1]+dp[i-1][j];
                }
                else
                    dp[i][j]=dp[i-1][j]; 
            }
        }
        return dp[m][n];
    }
};

