class Solution {
public:
    Node* connect(Node* root) {
        Node* parent=root;
        Node* child=NULL;
        Node* childhead=NULL;

        while(parent!=NULL){
            while(parent!=NULL){
            if(parent->left){
                if(childhead==NULL){
                    childhead=parent->left;

                }
                else{
                    child->next=parent->left;
                }
                child=parent->left;
            }
             if(parent->right){
                if(childhead==NULL){
                    childhead=parent->right;

                }
                else{
                    child->next=parent->right;
                }
                child=parent->right;
            }
            parent=parent->next;
        }
        parent=childhead;
        childhead=child=NULL;
        }
        return root;
    }
};

