class Solution {
public:
    Node* visited[102];

    void dfs(Node* curr, Node* temp){
        visited[temp->val]=temp;
        for(auto u: curr->neighbors){
            if(visited[u->val]==NULL){
                Node* v=new Node(u->val);
                temp->neighbors.push_back(v);
                dfs(u, v);
            }
            else
                temp->neighbors.push_back(visited[u->val]);
        }
    }

    Node* cloneGraph(Node* node) {
        if(node==NULL)
            return NULL;
        memset(visited, NULL, sizeof(visited));
        Node* copy=new Node(node->val);
        visited[node->val]=copy;
        for(auto curr: node->neighbors){
            if(visited[curr->val]==NULL){
                Node* temp=new Node(curr->val);
                copy->neighbors.push_back(temp);
                dfs(curr, temp);
            }
            else{
                copy->neighbors.push_back(visited[curr->val]);
            }
        }
        return copy;
    }
};

class Solution {
public:
    int canCompleteCircuit(vector<int>& gas, vector<int>& cost) {
        bool f=true;
        int ans=0;
        int n=gas.size();
        if(n==1){
            if(gas[0]>=cost[0])
                return 0;
            else
                return -1;
        }
        for(int i=0;i<n;i++){
            if(gas[i]>=cost[i]){
               int j=i;
               int c=gas[j]-cost[j]+gas[(j+1)%n];
               j=(j+1)%n;
                while(j!=i){
                  if(c<cost[j])
                    break;
                  c=c-cost[j]+gas[(j+1)%n];
                  j=(j+1)%n;
                }
                if(j==i)
                  return i; 
            }
        }
        return -1;
    }
};

class Solution {
public:
    int candy(vector<int>& ratings) {
        int n=ratings.size();
        if(n==1)
            return 1;
        vector<int> l(n,1);
        vector<int> r(n,1);
        for(int i=1;i<n;i++){
            if(ratings[i]>ratings[i-1])
                l[i]=l[i-1]+1;
        }
        for(int i=n-2;i>=0;i--){
            if(ratings[i]>ratings[i+1])
                r[i]=r[i+1]+1;
        }
        int s=0;
        for(int i=0;i<n;i++)
            s+=max(l[i],r[i]);
        return s;
    }
};

