class BSTIterator {
public:
    stack<TreeNode*> s;
    BSTIterator(TreeNode* root) {
        while(root){
            s.push(root);
            root=root->left;
        }
    }

    int next() {
        TreeNode* t=s.top();
        s.pop();
        int data=t->val;
        t=t->right;
        while(t!=NULL){
            s.push(t);
            t=t->left;
        }
        return data;
    }

    bool hasNext() {
        return (!s.empty());
    }
};

