class Solution {
public:

    bool isCyclic(int v, vector<int> &ans, vector<int> &vis, vector<vector<int>> &adj){
        vis[v]=-1;
        for(int u: adj[v]){
            if(vis[u]==-1)
                return true;
            if(vis[u]==0 && isCyclic(u, ans, vis, adj))
                return true;
        }
        vis[v]=1;
        ans.push_back(v);
        return false;
    }

    vector<int> findOrder(int numCourses, vector<vector<int>>& prerequisites) {
        vector<vector<int>> adj(numCourses);
        for(int i=0;i<prerequisites.size();i++)
            adj[prerequisites[i][0]].push_back(prerequisites[i][1]);
        vector<int> vis(numCourses,0);
        vector<int> ans;
        for(int i=0;i<numCourses;i++){
            if(!vis[i]){
                if(isCyclic(i, ans, vis, adj))
                    return {};
            }
        }
        return ans;
    }
};

class WordDictionary
{
public:
    struct Node
    {
        Node *links[26];
        bool flag = false;
        bool containsKey(char key)
        {
            return links[key - 'a'];
        }
        bool hasEnd()
        {
            return flag;
        }
        Node *getNode(char key)
        {
            return links[key - 'a'];
        }
        void put(char key)
        {
            links[key - 'a'] = new Node();
        }
        void setEnd()
        {
            flag = true;
        }
    };
    Node *root;
    WordDictionary()
    {
        root = new Node();
    }

    void addWord(string word)
    {
        Node *p = root;
        for (char key : word)
        {
            if (!p->containsKey(key))
            {
                p->put(key);
            }
            p = p->getNode(key);
        }
        p->setEnd();
    }

    bool search(string word)
    {
        return advanceSearchHelper(word, 0, root);
    }
    bool advanceSearchHelper(string &word, int i, Node *dummy)
    {
        if (word.size() == i)
        {
            return dummy->hasEnd();
        }
        if (word[i] != '.')
        {
            if (dummy->containsKey(word[i]))
            {
                if (advanceSearchHelper(word, i + 1, dummy->getNode(word[i])))
                {
                    return true;
                }
            }
            else
            {
                return false;
            }
        }
        else
        {
            for (auto node : dummy->links)
            {
                if (node)
                {
                    if (advanceSearchHelper(word, i + 1, node))
                    {
                        return true;
                    };
                }
            }
        }
        return false;
    }
};
