        }

        vector<string> res; 

        helper(s, 0, cntL, cntR, res);

        return res;
    }
     void helper(string s, int start, int cntL, int cntR, vector<string>& res) {
        if (cntL == 0 && cntR == 0) {
            if (isValid(s)) res.push_back(s);
        }

        for (int i = start; i < s.size(); i++) {
            if (i > start && s[i] == s[i - 1]) continue;
            if (s[i] == '(' && cntL > 0) {
                string ss = s.substr(0, i) + s.substr(i + 1);
                helper(ss, i, cntL - 1, cntR, res);
            }
            if (s[i] == ')' && cntR > 0) {
                string ss = s.substr(0, i) + s.substr(i + 1);
                helper(ss, i, cntL, cntR - 1, res);
            }
        }
    }

    bool isValid(string s) {
        int count = 0;

        for (const char& c: s) {
            if (c == '(') count++;
            if (c == ')') {
                if (count == 0) return false;
                else count--;
            }
        }

        return count == 0;
    }
};

class NumArray {
public:
    int n;
    int st[1200005];

    void build(int si, int ss, int se, vector<int>& nums){
    if(ss==se){
        st[si]=nums[ss];
        return;
    }
    int mid=(ss+se)/2;
    build(2*si+1, ss, mid, nums);
    build(2*si+2, mid+1, se, nums);

    st[si]=st[2*si+1] + st[2*si+2];
    }


    int query(int si,int ss,int se,int qs,int qe)
    {

        if(qs<=ss && qe>=se)  
        {
            return st[si];
        }
        if(qs>se || qe<ss) 
            return 0;   

        int mid=(ss+se)/2;
        int left=query(2*si+1,ss,mid,qs,qe);
        int right=query(2*si+2,mid+1,se,qs,qe);
        return left+right;
    }

    void up(int si,int ss,int se,int qi, int val){
        if(ss==se){
            st[si]=val;
            return;
        }
        int mid=(ss+se)/2;
        if(qi<=mid)
            up(2*si+1,ss,mid,qi,val);
        else
            up(2*si+2,mid+1,se,qi,val);
        st[si]=st[2*si+1]+st[2*si+2];
    }

    NumArray(vector<int>& nums) {
        n=nums.size();
        build(0,0,n-1, nums);
    }

    void update(int index, int val) {
        return up(0,0,n-1,index, val);
    }

    int sumRange(int left, int right) {
        return query(0,0,n-1,left,right);
    }
};

