class Solution {
public:
    int wiggleMaxLength(vector<int>& nums) {
        int n=nums.size();
        if(n<2)
            return n;
        int prev=nums[1]-nums[0];
        int c=0;
        if(prev==0)
            c=1;
        else
            c=2;
        for(int i=2;i<n;i++){
            int next=nums[i]-nums[i-1];
            if((next>0 && prev<=0) || (next<0 && prev>=0))
            {
                c++;
                prev=next;
            }
        }
        return c;
    }
};

class Solution {
public:
    int kthSmallest(vector<vector<int>>& A, int k) {
        int M = A.size() ;
        int N = A[0].size();
        int l = A[0][0] ;          // low 
        int h = A[M-1][N-1];       // high 

        if( l == h )return l ;     // base case 

        int t = N*M - k ;          // looking for number of elements greater than me 

        while( l <= h )             // simple binary search 
        {
            int m = (l+h)/2 ; 

            int cnt = 0 ; 

            for( auto x : A )
            {
                cnt += x.end() - upper_bound( x.begin() , x.end() , m )  ;  
            }

            if( cnt <= t )h = m-1; 
            else l = m+1; 
        }

        return l;
    }
};

