class Solution {
public:
    vector<vector<int>> levelOrder(Node* root) {
        vector<vector<int>> ans;
        if(root==NULL)
            return ans;
        queue<Node*> q;
        q.push(root);
        while(!q.empty()){
            int k=q.size();
            vector<int> v;
            while(k--){
                Node* curr=q.front();
                    q.pop();
                v.push_back(curr->val);
                int sz=curr->children.size();
                for(int i=0;i<sz;i++){
                    if(curr->children[i]!=NULL)
                        q.push(curr->children[i]);
                }
            }
            ans.push_back(v);
        }
        return ans;
    }
};

