 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    int findBottomLeftValue(TreeNode* root) {
        if(root==NULL)
            return -1;
        queue<TreeNode*> q;
        q.push(root);
        int ans=0;
        while(!q.empty()){
            TreeNode* curr=q.front();
            q.pop();
            ans=curr->val;
            if(curr->right)
                q.push(curr->right);
            if(curr->left)
                q.push(curr->left);
        }
        return ans;
    }
};

class Solution {
public:
    int longestPalindromeSubseq(string s) {
        string a=s;
        string str=s;
        reverse(str.begin(), str.end());
        string b=str;
        int n=s.size();
        int t[n+1][n+1];
        for(int i=0;i<=n;i++)
            t[i][0]=0;
        for(int i=0;i<=n;i++)
            t[0][i]=0;
        for(int i=1;i<=n;i++){
            for(int j=1;j<=n;j++){
              if(a[i-1]==b[j-1])
                  t[i][j]=1+t[i-1][j-1];
              else
                  t[i][j]=max(t[i-1][j],t[i][j-1]);
           }
        }
        return t[n][n];
    }
};

