/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    vector<ListNode*> splitListToParts(ListNode* root, int k) {
        vector<ListNode*> ans(k, NULL);
        int len = 0;
        for (ListNode* node = root; node; node = node->next)
            len++;
        int n = len / k;
        int r = len % k; 
        // n : minimum guaranteed part size; 
        // r : extra nodes spread to the first r parts;

        ListNode* node = root;
        ListNode* prev = NULL;
        for (int i = 0; node && i < k; i++, r--) {
            ans[i] = node;
            for (int j = 0; j < n + (r > 0); j++) {
                prev = node;
                node = node->next;
            }
            prev->next = NULL;
        }
        return ans;
    }
};

class Solution {
public:
    vector<int> asteroidCollision(vector<int>& asteroids) {
        int n=asteroids.size();
        vector<int> ans;
        stack<int> s;
        //cases
        // stack top --- incoming asteroid
        // left          left         nothing happens
        // left          right        nothing happens
        // right         left         collision (+-)
        // right          right       nothing happens
        for(int i=0;i<n;i++){
            if(s.empty()){
                s.push(asteroids[i]);
            }
            else{
                if(s.top()>0 && asteroids[i]<0){
                    bool f=false;
                    while(!s.empty() && s.top()>0 && asteroids[i]<0 && abs(asteroids[i])>abs(s.top())){
                        s.pop();
                        f=true;
                    }
                    bool g=false;
                    if(!s.empty() && s.top()>0 && asteroids[i]<0 && abs(asteroids[i])==abs(s.top())){
                        s.pop();
                        g=true;
                    }
                    if(!s.empty() && s.top()>0 && asteroids[i]<0 && abs(asteroids[i])<abs(s.top())){
                        g=true;
                    }
                    if(f && !g)
                        s.push(asteroids[i]);
                }
                else {
                    s.push(asteroids[i]);
                }
            }
        }
        while(!s.empty()){
            ans.push_back(s.top());
            s.pop();
        }
        reverse(ans.begin(), ans.end());
        return ans;
    }
};

