            return false;
        if(tx==sx)
            return (ty-sy)%sx==0;
        if(ty==sy)
            return (tx-sx)%sy==0;
        if(tx<ty)
            ty%=tx;
        else
            tx%=ty;
        return reachingPoints(sx,sy,tx,ty);
    }
};

