class Solution {
public:
    int shortestSubarray(vector<int>& A, int K) {
        int N = A.size(), res = N + 1;
        deque<int> d;
        for (int i = 0; i < N; i++) {
            if (i > 0)
                A[i] += A[i - 1];
            if (A[i] >= K)
                res = min(res, i + 1);
            while (d.size() > 0 && A[i] - A[d.front()] >= K)
                res = min(res, i - d.front()), d.pop_front();
            while (d.size() > 0 && A[i] <= A[d.back()])
                d.pop_back();
            d.push_back(i);
        }
        return res <= N ? res : -1;
    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Solution {
public:

    unordered_map<TreeNode*, TreeNode*> m;
    vector<int> ans;

    void findParent(TreeNode* root){
        if(root==NULL)
            return;
        if(root->left)
        m[root->left]=root;
        if(root->right)
        m[root->right]=root;

        findParent(root->left);
        findParent(root->right);
    }

    vector<int> distanceK(TreeNode* root, TreeNode* target, int k) {
        if(root==NULL)
            return ans;

        findParent(root);
        unordered_set<TreeNode*> vis;

        queue<TreeNode*> q;
        q.push(target);
        while(!q.empty()){
            int n=q.size();
            while(n--){
            TreeNode* curr=q.front();
            q.pop();
            vis.insert(curr);
            if(k==0){
                ans.push_back(curr->val);
            }
            if(m.count(curr)>0 && vis.count(m[curr])==0){
                q.push(m[curr]);
            }
            if(curr->left && vis.count(curr->left)==0){
                q.push(curr->left);
            }
            if(curr->right && vis.count(curr->right)==0){
                q.push(curr->right);
            }
          }
          k--;
          if(k<0)
            break;
        }
        return ans;
    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:

    TreeNode* lca(TreeNode* l1, TreeNode* l2, TreeNode* root){
        if(root==NULL || root==l1 || root==l2)
            return root;
        TreeNode* l=lca(l1,l2,root->left);
        TreeNode* r=lca(l1,l2,root->right);
        if(l&&r)
            return root;
        if(!l)
            return r;
        return l;
    }

    TreeNode* subtreeWithAllDeepest(TreeNode* root) {
        if(root==NULL)
            return NULL;
        TreeNode* f, *s;
        queue<TreeNode*> q;
        q.push(root);
        while(!q.empty()){
            int k=q.size();
            for(int i=0;i<k;i++){
                TreeNode* curr=q.front();
                q.pop();
                if(i==0)
                    f=curr;
                if(i==k-1)
                    s=curr;
                if(curr->left)
                    q.push(curr->left);
                if(curr->right)
                    q.push(curr->right);
            }
        }
        return lca(f,s, root);
    }
};

