        return arr;
    }
};

class Solution {
public:
    int dx[8] = {0,0,1,-1,1,1,-1,-1};
    int dy[8] = {1,-1,0,0,1,-1,-1,1};

    int shortestPathBinaryMatrix(vector<vector<int>>& grid) {
        int n=grid.size();
        int m=grid[0].size();
        if(grid[0][0]!=0 || grid[n-1][m-1]!=0)
            return -1;
        int ans=0;
        queue<pair<int,int>> q;
        q.push({0,0});
        while(!q.empty()){
            int k=q.size();
            ans++;
            while(k--){
                int x=q.front().first;
                int y=q.front().second;
                q.pop();
                if(x==n-1 && y==m-1)
                   return ans;
                for(int i=0;i<8;i++){
                   int xx=x+dx[i];
                   int yy=y+dy[i];
                    if(xx>=0 && yy>=0 && xx<n && yy<m && grid[xx][yy]==0){
                        q.push({xx,yy});
                        grid[x][y]=1;
                        grid[xx][yy]=1;
                    }
               }
            }
        }
        return (grid[n-1][m-1]==1)?ans:-1;  
    }
};

class Solution {
public:
    string shortestCommonSupersequence(string a, string b) {
        int m=a.size();
        int n=b.size();
        int t[m+1][n+1];
        for(int i=0;i<=m;i++)
            t[i][0]=0;
        for(int i=0;i<=n;i++)
            t[0][i]=0;
        for(int i=1;i<=m;i++){
            for(int j=1;j<=n;j++){
                if(a[i-1]==b[j-1])
                    t[i][j]=1+t[i-1][j-1];
                else
                    t[i][j]=max(t[i-1][j], t[i][j-1]);
            }
        }
        int i=m,j=n;
        string ans;
        while(i>0 && j>0){
            if(a[i-1]==b[j-1]){
                ans.push_back(a[i-1]);
                i--;
                j--;
            }
            else if(t[i-1][j]>t[i][j-1]){
                ans.push_back(a[i-1]);
                i--;
            }
            else{
                ans.push_back(b[j-1]);
                j--;
            }   
        }
        while(i>0){
           ans.push_back(a[i-1]);
           i--; 
        }
         while(j>0){
           ans.push_back(b[j-1]);
           j--; 
        }
        reverse(ans.begin(), ans.end());
        return ans;
    }
};

