        memset(t,0,sizeof(t));
        for(int i=1;i<n+1;i++){
            for(int j=1;j<m+1;j++){
                if(text1[i-1]==text2[j-1])
                    t[i][j]=1+t[i-1][j-1];
                else
                    t[i][j]=max(t[i][j-1], t[i-1][j]);
            }
        }
        return t[n][m];
    }
};

class Solution {
public:
    int t[32][1001]; //dices and target
    int mod=1e9+7;
    int solve(int d, int f, int target){
        if(d==0){
            if(target==0)
                return 1;
            return 0;
        }
        if(target<0)
                return 0;
        if(d*f<target)
            return 0;
        if(d*f==target)
            return 1;
        if(t[d][target]!=-1)
            return t[d][target];
        long long ans=0;
        for(int i=1;i<=f;i++){
            ans=(ans+solve(d-1, f, target-i))%mod;
        }
        return t[d][target]=ans;
    }


    int numRollsToTarget(int d, int f, int target) {
        memset(t,-1,sizeof(t));
        return solve(d,f,target);
    }
};

class Solution {
public:
    int dx[4]={1,0,-1,0};
    int dy[4]={0,1,0,-1};

    int maxDistance(vector<vector<int>>& grid) {
        queue<pair<int,int>> q;
        int n=grid.size();
        int m=grid[0].size();
        for(int i=0;i<n;i++){
            for(int j=0;j<m;j++){
                if(grid[i][j]==1)
                    q.push({i,j});
            }
        }
        int ans=0;
        if(q.size()==n*m)
            return -1;
        while(!q.empty()){
            int k=q.size();
            ans++;
            for(int i=0;i<k;i++){
                int x=q.front().first;
                int y=q.front().second;
                q.pop();
                for(int i=0;i<4;i++){
                    int xx=x+dx[i];
                    int yy=y+dy[i];
                    if(xx>=0 && yy>=0 && xx<n && yy<n && grid[xx][yy]==0){
                        q.push({xx,yy});
                        grid[xx][yy]=1;
                    }
                }
            }
        }
        return ans-1;
    }
};

