class Solution {
public:
    int findMinFibonacciNumbers(int k) {
        //variables a,b,c help us in finding the Fibonacci series
        long long a=1,b=1,c=a+b;
        //vector c stores the fibonacci series for us
        vector<long long> v;
        v.push_back(1);
        while(c<=k){
            v.push_back(c);
            a = b;
            b = c;
            c= a+b;
        }
        v.push_back(c);
        //ans is what we will return ie the min no of Fibonacci nos which will sum to k
        int ans = 0;
        int size = v.size()-1;
        //while loop iterates over v until we get the sum k with the nos
        while(true){
          //if the  
          if(v[size]==k){
              return ans+1;
          }
          //deducting the max no less than k which we get and update k and then increase the ans variable 
            else if(v[size]<k){
               k = k - v[size];
               ans++;
           }
           //decrementing the size variable to point to the next smaller no in the vector v  
           size--;
        }
        return ans;
    }
};

class Solution {
public:
    int longestSubarray(vector<int>& nums, int limit) {
        int n=nums.size();
        deque<int> incq;
        deque<int> decq;
        int i=0,j=0;
        int ans=0;
        while(j<n){
            int x=nums[j];
            while(!incq.empty() && nums[incq.back()]>=x)
                incq.pop_back();
            while(!decq.empty() && nums[decq.back()]<=x)
                decq.pop_back();
            incq.push_back(j);
            decq.push_back(j);

            int mini=nums[incq.front()];
            int maxi=nums[decq.front()];

            if(maxi-mini<=limit){
                ans=max(ans, j-i+1);
            }
            else{
                i++;
                if(i>incq.front()){
                    incq.pop_front();
                }
                if(i>decq.front()){
                    decq.pop_front();
                }
            }
            j++;
        }
        return ans;
    }
};

