    int minDays(vector<int>& bloomDay, int m, int k) {
        int l=1;
        int r=1;
        int n=bloomDay.size();
        if((long long)n<(long long)m*k)
            return -1;
        for(int i=0;i<n;i++)
            r=max(r, bloomDay[i]);
        while(l<r){
            long long mid=(long long)l+(r-l)/2;
